/**
 * Get the RFE indicator for a contribution, if any.
 */
export function getRFEIndicator(description: string, type?: string): RFEIndicator | null {
  // Try direct description lookup first
  const key = DESC_TO_KEY[description];
  if (key && RFE_LOOKUP[key]) return RFE_LOOKUP[key];

  // Try pattern matching
  // Aspect: "A's planet1 aspect B's planet2" (synastry only — owners must differ)
  const aspectMatch = description.match(/^([AB])'s\s+(\w+)\s+(conjunction|trine|sextile|opposition|square|quincunx|copresence)\s+([AB])'s\s+(\w+)$/i);
  if (aspectMatch) {
    const [, owner1, p1, aspect, owner2, p2] = aspectMatch;
    // Only match synastry aspects (A↔B), not natal aspects (A↔A or B↔B)
    if (owner1 !== owner2) {
      const sorted = [p1.toLowerCase(), p2.toLowerCase()].sort();
      const k = `aspect:${sorted[0]}-${sorted[1]}:${aspect.toLowerCase()}`;
      if (RFE_LOOKUP[k]) return RFE_LOOKUP[k];
    }
  }

  // Composite: "Composite Planet in Sign: ..."
  const compMatch = description.match(/^Composite\s+(\w+)\s+in\s+(\w+)/i);
  if (compMatch) {
    const k = `composite:${compMatch[1].toLowerCase()}:${compMatch[2].toLowerCase()}`;
    if (RFE_LOOKUP[k]) return RFE_LOOKUP[k];
  }

  // Mercury-North Node
  const mercNNMatch = description.match(/^[AB]'s\s+Mercury\s+(trine|sextile|conjunction|opposition|square)\s+North\s+Node$/i);
  if (mercNNMatch) {
    const k = `longevity:mercury-northnode:${mercNNMatch[1].toLowerCase()}`;
    if (RFE_LOOKUP[k]) return RFE_LOOKUP[k];
  }

  return null;
}
